def ker_1(x_1, x_2):
    return -np.dot(x_1-x_2, x_1-x_2)

def ker_2(x_1, x_2):
    return np.exp(ker_1(x_1, x_2))

SVM_model_1 = svm.SVC(kernel=ker_1)
SVM_model_1.fit(X_train, t_train)
prediction_1 = SVM_model_1.predict(X_test)

SVM_model_2 = svm.SVC(kernel=ker_2)
SVM_model_2.fit(X_train, t_train)
prediction_2 = SVM_model_2.predict(X_test)

print(accuracy_score(t_test, prediction_2) - accuracy_score(t_test, prediction_1))
